parameters.content:
/**
 * Notification data models and types.
 *
 * Defines the core types for the notification system. All notifications
 * flow through the EventBus and are delivered via NotificationAdapter
 * implementations (email, webhook, in-app, etc.).
 */

/** Supported notification channels. Adapters implement one channel each. */
export type NotificationChannel = 'email' | 'webhook' | 'in-app';

/** Categories of notifications for filtering and routing. */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'user_welcome'
  | 'user_update'
  | 'system_alert';

/** Priority levels affect delivery urgency and retry behavior. */
export type NotificationPriority = 'low' | 'normal' | 'high' | 'critical';

/** Status of a notification through its lifecycle. */
export type NotificationStatus = 'pending' | 'sent' | 'failed';

/**
 * The payload passed to adapters for delivery.
 * Adapters receive this and translate it to channel-specific formats.
 */
export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  type: NotificationType;
  priority: NotificationPriority;
  metadata?: Record<string, string>;
}

/**
 * A persisted notification record with delivery status.
 */
export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  channel: NotificationChannel;
  type: NotificationType;
  priority: NotificationPriority;
  status: NotificationStatus;
  metadata?: Record<string, string>;
  sentAt: Date;
}

/**
 * NotificationAdapter interface — the contract all notification delivery
 * adapters must implement.
 *
 * ARCHITECTURAL CONSTRAINT: Every notification channel (email, webhook,
 * in-app, SMS, etc.) MUST be implemented as a NotificationAdapter.
 * The NotificationService routes payloads to the appropriate adapter
 * based on the payload's `channel` field. Adapters are registered with
 * the NotificationService via `registerAdapter()`.
 *
 * To add a new notification channel:
 * 1. Add the channel name to NotificationChannel in models/notification.ts
 * 2. Create an adapter class implementing this interface
 * 3. Register it with NotificationService.registerAdapter()
 */

import type { NotificationChannel, NotificationPayload } from '../models/notification.js';

/**
 * Result of an adapter's send attempt.
 */
export interface NotificationResult {
  success: boolean;
  /** Adapter-specific identifier for the sent notification (e.g., email message ID). */
  externalId?: string;
  /** Error message if delivery failed. */
  error?: string;
}

/**
 * All notification adapters must implement this interface.
 */
export interface NotificationAdapter {
  /** The channel this adapter handles. Must be unique per NotificationService. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must not throw — return a failed NotificationResult instead.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter.
 *
 * Implements the NotificationAdapter interface for the 'email' channel.
 * Currently a stub that logs emails in-memory. Replace the send() method
 * with a real SMTP/API integration for production use.
 */

import type { NotificationAdapter, NotificationResult } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** Record of an email that was "sent" (logged in-memory). */
export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  /**
   * Send an email notification.
   * Stub implementation — stores the email in-memory for testing.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: SentEmail = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };

    this.sentEmails.push(email);

    return {
      success: true,
      externalId: `email-${this.sentEmails.length}`,
    };
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent emails. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

